import stylesText from './exercise-create-form.css?inline';
import { cssStyleSheet } from '../../../utils/css.js';
import { EXERCISE_CATEGORIES, EXERCISE_DEFAULT_UNITS } from '@motivation/shared';
import type { Exercise, NewExercise, ExerciseCategory, ExerciseDefaultUnit } from '@motivation/shared';

const styles = cssStyleSheet(stylesText);

/**
 * Derive a canonical_name from a display name: lowercase, non-alphanumeric runs
 * collapse to `_`, trimmed of leading/trailing `_`. "Cable Crunch" → "cable_crunch".
 * Mirrors the seed's snake_case keys so created and seeded names share a shape.
 */
export function deriveCanonicalName(displayName: string): string {
    return displayName.trim().toLowerCase().replace(/[^a-z0-9]+/g, '_').replace(/^_+|_+$/g, '');
}

const template = document.createElement('template');
template.innerHTML = `
    <form class="ex-form" novalidate>
        <label class="ex-form__field">
            <span>Name</span>
            <input type="text" id="name" class="ex-form__input" placeholder="e.g. Cable Crunch" autocomplete="off">
        </label>

        <div class="ex-form__row">
            <label class="ex-form__field">
                <span>Category</span>
                <select id="category" class="ex-form__input">
                    ${EXERCISE_CATEGORIES.map((c) => `<option value="${c}">${c.charAt(0).toUpperCase() + c.slice(1)}</option>`).join('')}
                </select>
            </label>
            <label class="ex-form__field">
                <span>Unit</span>
                <select id="unit" class="ex-form__input">
                    ${EXERCISE_DEFAULT_UNITS.map((u) => `<option value="${u}">${u}</option>`).join('')}
                </select>
            </label>
        </div>

        <fieldset class="ex-form__tracks">
            <legend>Tracks</legend>
            <label><input type="checkbox" id="tracks_reps" checked> Reps</label>
            <label><input type="checkbox" id="tracks_weight" checked> Weight</label>
            <label><input type="checkbox" id="tracks_duration"> Duration</label>
        </fieldset>

        <p class="ex-form__error" id="error" hidden></p>

        <div class="ex-form__actions">
            <button type="button" class="ex-form__btn" id="cancel">Cancel</button>
            <button type="submit" class="ex-form__btn ex-form__btn--primary" id="submit">Create</button>
        </div>
    </form>
`;

/**
 * Reusable "create exercise" form (story 177). Emitted via callbacks so both the
 * strength-logging picker (create-and-add mid-session) and the exercise
 * management screen can drive it. Derives `canonical_name` from the name and
 * defaults the tracking flags sensibly; the caller does the actual POST.
 */
export class ExerciseCreateForm extends HTMLElement {
    private _onSubmit: ((payload: NewExercise) => void) | null = null;
    private _onCancel: (() => void) | null = null;

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));
    }

    connectedCallback(): void {
        const shadow = this.shadowRoot!;
        shadow.querySelector('form')!.addEventListener('submit', (e) => { e.preventDefault(); this.handleSubmit(); });
        shadow.getElementById('cancel')!.addEventListener('click', () => this._onCancel?.());

        // Bodyweight movements usually don't carry external load — nudge the
        // weight flag off when the unit says bodyweight (still user-overridable).
        shadow.getElementById('unit')!.addEventListener('change', (e) => {
            const unit = (e.target as HTMLSelectElement).value;
            if (unit === 'bodyweight') this.weightInput.checked = false;
        });
    }

    /** Prefill the name (e.g. from the picker's search query) and focus it. */
    set presetName(value: string) {
        this.nameInput.value = value;
        // Defer focus until connected/painted.
        queueMicrotask(() => this.nameInput.focus());
    }

    /** Edit mode: prefill every field from an existing exercise and relabel submit. */
    set exercise(ex: Exercise) {
        const shadow = this.shadowRoot!;
        this.nameInput.value = ex.display_name;
        (shadow.getElementById('category') as HTMLSelectElement).value = ex.category;
        (shadow.getElementById('unit') as HTMLSelectElement).value = ex.default_unit;
        (shadow.getElementById('tracks_reps') as HTMLInputElement).checked = ex.tracks_reps === 1;
        this.weightInput.checked = ex.tracks_weight === 1;
        (shadow.getElementById('tracks_duration') as HTMLInputElement).checked = ex.tracks_duration === 1;
        shadow.getElementById('submit')!.textContent = 'Save';
    }

    set onSubmit(handler: (payload: NewExercise) => void) { this._onSubmit = handler; }
    set onCancel(handler: () => void) { this._onCancel = handler; }

    private get nameInput(): HTMLInputElement { return this.shadowRoot!.getElementById('name') as HTMLInputElement; }
    private get weightInput(): HTMLInputElement { return this.shadowRoot!.getElementById('tracks_weight') as HTMLInputElement; }

    private handleSubmit(): void {
        const shadow = this.shadowRoot!;
        const errorEl = shadow.getElementById('error')!;
        const displayName = this.nameInput.value.trim();
        const canonical = deriveCanonicalName(displayName);

        if (!displayName || !canonical) {
            errorEl.textContent = 'Enter a name.';
            errorEl.hidden = false;
            return;
        }
        errorEl.hidden = true;

        const payload: NewExercise = {
            canonical_name: canonical,
            display_name: displayName,
            category: (shadow.getElementById('category') as HTMLSelectElement).value as ExerciseCategory,
            default_unit: (shadow.getElementById('unit') as HTMLSelectElement).value as ExerciseDefaultUnit,
            tracks_reps: (shadow.getElementById('tracks_reps') as HTMLInputElement).checked ? 1 : 0,
            tracks_weight: this.weightInput.checked ? 1 : 0,
            tracks_duration: (shadow.getElementById('tracks_duration') as HTMLInputElement).checked ? 1 : 0,
        };
        this._onSubmit?.(payload);
    }

    /** Surface a server-side failure (e.g. duplicate) without losing entered values. */
    showError(message: string): void {
        const errorEl = this.shadowRoot!.getElementById('error')!;
        errorEl.textContent = message;
        errorEl.hidden = false;
    }
}

if (!customElements.get('exercise-create-form')) {
    customElements.define('exercise-create-form', ExerciseCreateForm);
}
